function capability(seed: CapabilitySeed): NexusCapability {
  return {
    ownerType: seed.ownerType ?? 'DEPARTMENT',
    ownerId: seed.ownerId ?? seed.departmentId,
    sourceType: seed.sourceType ?? 'NEXUS_NATIVE',
    supportingDepartments: seed.supportingDepartments ?? [],
    permissions: seed.permissions ?? [],
    estimatedMonthlyCost: seed.estimatedMonthlyCost ?? null,
    costNotes: seed.costNotes ?? 'No exact pricing asserted by Capability OS.',
    healthFreshness: seed.healthFreshness ?? 'REPORT_BACKED',
    lastVerifiedAt: seed.lastVerifiedAt ?? observedAt,
    eventsConsumed: seed.eventsConsumed ?? [],
    eventsEmitted: seed.eventsEmitted ?? [],
    maintenanceOwner: seed.maintenanceOwner ?? seed.departmentId,
    ...seed,
  };
}

