export function getCapabilityRegistry(): NexusCapability[] {
  const connectorCapabilities = getConnectorRegistry()
    .filter((connector) => !staticCapabilities.some((capability) => capability.capabilityId === `${connector.id}_connector` || capability.capabilityId === connector.id))
    .map((connector) => capability({
      capabilityId: `${connector.id}_connector`,
      name: `${connector.name} Connector`,
      description: connector.purpose,
      capabilityType: 'CONNECTOR' as CapabilityType,
      departmentId: connector.feature.toLowerCase().includes('research') ? 'research' : connector.feature.toLowerCase().includes('email') ? 'customer_support' : connector.feature.toLowerCase().includes('payment') || connector.feature.toLowerCase().includes('checkout') ? 'finance' : 'engineering',
      sourceType: 'CONFIG_BACKED',
      activationMode: connector.status === 'configured_safe' ? 'READ_ONLY' : connector.status === 'future_only' ? 'DEFERRED' : connector.safety === 'blocked' ? 'BLOCKED_BY_POLICY' : connector.status === 'missing_key' || connector.status === 'missing_env' ? 'NOT_CONFIGURED' : 'APPROVAL_GATED',
      approvalLevel: connector.approvalRequired ? 'RAY_REVIEW' : 'OPERATOR',
      securityClass: connector.safety === 'blocked' ? 'HIGH_RISK' : 'RESTRICTED' as CapabilitySecurityClass,
      allowedDataClasses: ['INTERNAL_METADATA'],
      prohibitedDataClasses: ['CLIENT_PII', 'CREDENTIALS'],
      permissions: connector.safety === 'read_only' ? ['read'] : [],
      credentialRequirements: connector.envVars,
      dependencies: [],
      costModel: 'UNKNOWN',
      healthSource: 'src/hermes/nexus/nexusConnectorRegistry.ts',
      healthStatus: connector.status === 'configured_safe' ? 'HEALTHY' : connector.status === 'future_only' ? 'DEFERRED' : connector.safety === 'blocked' ? 'BLOCKED' : 'NOT_CONFIGURED' as CapabilityHealthStatus,
      tests: ['tests/nexus_connector_registry.test.ts'],
      rollbackPlan: 'Leave connector unconfigured or disabled.',
      disablePlan: 'Remove connector from active routing.',
      hermesMayRecommend: connector.safety !== 'blocked',
      hermesMayExecute: false,
      alphaMayUse: connector.feature.toLowerCase().includes('research') && connector.safety === 'read_only',
      clientAiMayUse: false,
      rayApprovalState: connector.approvalRequired ? 'PENDING' : 'NOT_REQUIRED',
      evidence: [ev('src/hermes/nexus/nexusConnectorRegistry.ts')],
    }));
  return [...staticCapabilities, ...connectorCapabilities];
}

export function getCapability(capabilityId: string): NexusCapability | undefined {
  return getCapabilityRegistry().find((capability) => capability.capabilityId === capabilityId);
}

export function buildCapabilityOSSummary(): CapabilityOSSummary {
  const capabilities = getCapabilityRegistry();
  const countBy = <T extends string>(items: T[]) => items.reduce<Record<string, number>>((acc, item) => {
    acc[item] = (acc[item] ?? 0) + 1;
    return acc;
  }, {});
  const proposals = buildCapabilityProposalsFromRepoIntelligence();
  return {
    generatedAt: new Date().toISOString(),
    total: capabilities.length,
    byActivationMode: countBy(capabilities.map((item) => item.activationMode)),
    byHealth: countBy(capabilities.map((item) => item.healthStatus)),
    approvalGated: capabilities.filter((item) => item.activationMode === 'APPROVAL_GATED').length,
    awaitingRayApproval: capabilities.filter((item) => item.rayApprovalState === 'PENDING').length,
    missingCredentials: capabilities.filter((item) => item.credentialRequirements.length && item.activationMode === 'NOT_CONFIGURED').length,
    dependencyBlocked: capabilities.filter((item) => item.healthStatus === 'BLOCKED' || item.healthStatus === 'PROHIBITED').length,
    proposals,
    capabilities,
  };
}

function licenseStatus(license: unknown): CapabilityProposal['licenseStatus'] {
  const value = String(license ?? '').toUpperCase();
  if (!value || value === 'UNKNOWN' || value === 'NOASSERTION') return 'UNKNOWN';
  if (value.includes('GPL') || value.includes('AGPL') || value.includes('SSPL')) return 'CONDITIONAL';
  return 'VERIFIED';
}

function dispositionToMode(disposition: string): CapabilityActivationMode {
  if (disposition === 'INTEGRATE_AS_CONTROLLED_EXTERNAL_TOOL') return 'NOT_CONFIGURED';
  if (disposition === 'REJECT') return 'PROHIBITED';
  if (disposition === 'DEFER') return 'DEFERRED';
  return 'READ_ONLY';
}

export function buildCapabilityProposalsFromRepoIntelligence(): CapabilityProposal[] {
  const candidates = Array.isArray((repoRegistry as { candidates?: unknown[] }).candidates) ? (repoRegistry as { candidates: Record<string, unknown>[] }).candidates : [];
  return candidates.map((candidate) => {
    const repository = `${String(candidate.repository_owner ?? 'unknown')}/${String(candidate.repository_name ?? 'unknown')}`;
    const disposition = String(candidate.proposed_disposition ?? 'DEFER') as CapabilityProposal['proposedDisposition'];
    return {
      proposalId: `proposal_${String(candidate.candidate_id ?? repository).replace(/[^a-z0-9_]+/gi, '_').toLowerCase()}`,
      candidateName: repository,
      sourceRepository: String(candidate.canonical_url ?? repository),
      sourceType: String(candidate.source_type ?? 'OPEN_SOURCE_OR_EXTERNAL_TOOL'),
      proposedCapabilityType: repository === 'github/github-mcp-server' ? 'MCP_SERVER' : 'RESEARCH_TOOL',
      proposedDepartment: String(candidate.department_owner ?? 'research'),
      businessProblem: String(candidate.exact_pattern_under_review ?? 'External capability evaluation'),
      proposedValue: String(candidate.business_value ?? 'UNKNOWN'),
      existingNexusOverlap: Array.isArray(candidate.existing_nexus_overlap) ? candidate.existing_nexus_overlap.map(String) : [],
      licenseStatus: licenseStatus(candidate.license),
      securityStatus: Array.isArray(candidate.security_advisories) && candidate.security_advisories.length ? 'PARTIAL' : 'UNKNOWN',
      proposedDisposition: disposition,
      requestedActivationMode: dispositionToMode(disposition),
      estimatedCost: String(candidate.operating_cost ?? candidate.estimated_subscription_savings ?? 'UNKNOWN'),
      dataRisk: String(candidate.privacy_risk ?? candidate.tenant_isolation_risk ?? 'UNKNOWN'),
      dependencies: [],
      evidence: Array.isArray(candidate.evidence_links) ? candidate.evidence_links.map(String) : [],
      status: disposition === 'REJECT' ? 'REJECTED' : disposition === 'DEFER' ? 'DEFERRED' : 'AWAITING_REVIEW',
      rayDecisionRequired: String(candidate.ray_decision ?? 'PENDING') === 'PENDING',
    };
  });
}
